import androidx.compose.ui.unit.dp
import androidx.compose.ui.unit.sp
import androidx.navigation.NavController

@Composable
fun LoadingScreen(zDefendManager: ZDefendManager, navController: NavController) {
    val isLoaded by zDefendManager.isLoaded
    val percentage by zDefendManager.percentage

    // Navigate to main screen as soon as the scan reaches 100 %
    LaunchedEffect(isLoaded) {
        if (isLoaded) {
            navController.navigate("zimperium") {
                popUpTo("loading") { inclusive = true }
            }
        }
    }

    // Smooth progress ring animation
    val animatedProgress by animateFloatAsState(
        targetValue = percentage / 100f,
        animationSpec = tween(durationMillis = 600, easing = FastOutSlowInEasing),
        label = "scan_progress"
    )

    // Pulsing "Scanning…" label
    val infiniteTransition = rememberInfiniteTransition(label = "pulse")
    val textAlpha by infiniteTransition.animateFloat(
        initialValue = 0.35f,
        targetValue = 1f,
        animationSpec = infiniteRepeatable(
            animation = tween(durationMillis = 900, easing = FastOutSlowInEasing),
            repeatMode = RepeatMode.Reverse
        ),
        label = "text_alpha"
    )

    Box(
        modifier = Modifier
            .fillMaxSize()
            .background(MaterialTheme.colorScheme.background),
        contentAlignment = Alignment.Center
    ) {
        Column(
            horizontalAlignment = Alignment.CenterHorizontally,
            verticalArrangement = Arrangement.Center,
            modifier = Modifier.padding(32.dp)
        ) {
            // Branding
            Text(
                text = "ZDefend",
                style = MaterialTheme.typography.headlineLarge,
                fontWeight = FontWeight.Bold,
                color = MaterialTheme.colorScheme.primary
            )

            Text(
                text = "Mobile Threat Defense",
                style = MaterialTheme.typography.bodyMedium,
                color = MaterialTheme.colorScheme.onBackground.copy(alpha = 0.6f)
            )

            Spacer(modifier = Modifier.height(48.dp))

            // Circular progress ring with percentage in the centre
            Box(
                contentAlignment = Alignment.Center,
                modifier = Modifier.size(180.dp)
            ) {
                CircularProgressIndicator(
                    progress = { animatedProgress },
                    modifier = Modifier.size(180.dp),
                    strokeWidth = 10.dp,
                    color = MaterialTheme.colorScheme.primary,
                    trackColor = MaterialTheme.colorScheme.surfaceVariant
                )

                Column(horizontalAlignment = Alignment.CenterHorizontally) {
                    Text(
                        text = "$percentage%",
                        fontSize = 40.sp,
                        fontWeight = FontWeight.Bold,
                        color = MaterialTheme.colorScheme.primary
                    )
                    Text(
                        text = "complete",
                        fontSize = 12.sp,
                        color = MaterialTheme.colorScheme.onBackground.copy(alpha = 0.5f)
                    )
                }
            }

            Spacer(modifier = Modifier.height(32.dp))

            // Pulsing status text
            Text(
                text = "Scanning device…",
                style = MaterialTheme.typography.bodyLarge,
                color = MaterialTheme.colorScheme.onBackground.copy(alpha = textAlpha)
            )
        }
    }
}

package com.dev.diet018

import android.os.Bundle
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.compose.material3.AlertDialog
import androidx.compose.material3.Text
import androidx.compose.material3.TextButton
import androidx.compose.runtime.getValue
import androidx.navigation.NavHostController
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import androidx.navigation.compose.rememberNavController
import com.dev.diet018.ui.theme.Diet018Theme
import com.google.firebase.Firebase
import com.google.firebase.auth.FirebaseAuth
import com.google.firebase.auth.auth
import com.google.firebase.firestore.FirebaseFirestore
import com.google.firebase.firestore.firestore

class MainActivity : ComponentActivity() {
    private lateinit var zDefendManager: ZDefendManager

    override fun onCreate(savedInstanceState: Bundle?) {
        auth = Firebase.auth
        db = Firebase.firestore
        zDefendManager = ZDefendManager.shared

        super.onCreate(savedInstanceState)
        setContent {
            Diet018Theme {
                val showAlert by zDefendManager.showAlert

                NavHost(navController = navController, startDestination = "login") {
                    composable("login") { LoginScreen(auth, navController) }
                    composable("register") { RegisterScreen(auth, navController) }
                    composable("dashboard") { DashboardScreen(auth, db, navController) }
                    composable("zimperium") { ZimperiumScreen(auth, zDefendManager, navController) }
                    composable("main") { MainScreen(auth, zDefendManager, navController) }
                    }
                }

                NavHost(navController = navController, startDestination = "zimperium") {
                    composable("zimperium") { ZimperiumScreen(zDefendManager, navController) }
                    composable("main") { MainScreen(zDefendManager, navController) }
                    composable("policies") { PolicyScreen(zDefendManager, navController) }
                    composable("troubleshoot") { TroubleshootScreen(zDefendManager, navController) }
                    composable("simulate") { SimulateScreen(zDefendManager, navController) }
                    composable("audit") { AuditScreen(zDefendManager, navController) }
                    composable("linked") { LinkedScreen(zDefendManager, navController) }
                    composable("status") { StatusScreen(zDefendManager, navController) }
                    composable("alert_screen") { AlertScreen(zDefendManager, navController) }
                }

                val currentUser = auth.currentUser
                if (currentUser != null) {
                    navController.navigate("zimperium")
                }
            }
        }
    }

    override fun onStart() {
        super.onStart()
        zDefendManager.initializeZDefendApi()
    }

    override fun onDestroy() {
        super.onDestroy()
        zDefendManager.deregisterZDefendApi()
    }
}

package com.dev.diet018

import android.os.Bundle
import androidx.activity.ComponentActivity
import androidx.activity.compose.setContent
import androidx.compose.runtime.LaunchedEffect
import androidx.compose.runtime.getValue
import androidx.navigation.NavHostController
import androidx.navigation.compose.NavHost
